from zeep import Client
from zeep.plugins import HistoryPlugin
from lxml import etree
import re


def sanitize_xml_input(user_input):
    """
    Sanitize user input to prevent XML injection attacks.
    Removes or escapes special XML characters.
    """
    if user_input is None:
        return ""
    
    # Convert to string
    user_input = str(user_input)
    
    # Remove any XML special characters and control characters
    # Replace XML special characters with their entity equivalents
    user_input = user_input.replace("&", "&amp;")
    user_input = user_input.replace("<", "&lt;")
    user_input = user_input.replace(">", "&gt;")
    user_input = user_input.replace('"', "&quot;")
    user_input = user_input.replace("'", "&apos;")
    
    # Remove control characters except tab, newline, and carriage return
    user_input = re.sub(r'[\x00-\x08\x0B-\x0C\x0E-\x1F\x7F]', '', user_input)
    
    # Remove any CDATA section markers
    user_input = user_input.replace("<![CDATA[", "")
    user_input = user_input.replace("]]>", "")
    
    # Remove XML processing instructions
    user_input = re.sub(r'<\?.*?\?>', '', user_input)
    
    # Remove XML comments
    user_input = re.sub(r'<!--.*?-->', '', user_input)
    
    return user_input


def validate_policy_number(policy_number):
    """
    Validate policy number format.
    Only allow alphanumeric characters and hyphens.
    """
    if not policy_number:
        raise ValueError("Policy number cannot be empty")
    
    # Allow only alphanumeric characters, hyphens, and limit length
    if not re.match(r'^[A-Za-z0-9\-]{1,50}$', policy_number):
        raise ValueError("Invalid policy number format. Only alphanumeric characters and hyphens allowed.")
    
    return policy_number


def validate_customer_name(customer_name):
    """
    Validate customer name format.
    Only allow letters, spaces, hyphens, and apostrophes.
    """
    if not customer_name:
        raise ValueError("Customer name cannot be empty")
    
    # Allow only letters, spaces, hyphens, apostrophes, and limit length
    if not re.match(r"^[A-Za-z\s\-']{1,100}$", customer_name):
        raise ValueError("Invalid customer name format. Only letters, spaces, hyphens, and apostrophes allowed.")
    
    return customer_name


